#[test]
fn test_uri_parsing_valid_format() {
    let uri_string = "http://localhost:8081/api/test";
    let result = uri_string.parse::<hyper::Uri>();
    assert!(result.is_ok());

    let uri = result.unwrap();
    assert_eq!(uri.path(), "/api/test");
}

#[test]
fn test_uri_parsing_with_query() {
    let uri_string = "http://localhost:8081/api?param=value";
    let result = uri_string.parse::<hyper::Uri>();
    assert!(result.is_ok());

    let uri = result.unwrap();
    assert_eq!(uri.path(), "/api");
    assert_eq!(uri.query(), Some("param=value"));
}

#[test]
fn test_disabled_entities_filter_empty_strings() {
    let header_value = "EMAIL,,PHONE";
    let entities: Vec<String> = header_value.split(',')
        .map(|s| s.trim().to_string())
        .filter(|s| !s.is_empty())
        .collect();

    assert_eq!(entities.len(), 2);
    assert_eq!(entities, vec!["EMAIL", "PHONE"]);
}

#[test]
fn test_disabled_entities_case_sensitive() {
    let header_value = "email,EMAIL,Email";
    let entities: Vec<String> = header_value.split(',').map(|s| s.trim().to_string()).collect();

    assert_eq!(entities.len(), 3);
    assert!(entities.contains(&"email".to_string()));
    assert!(entities.contains(&"EMAIL".to_string()));
    assert!(entities.contains(&"Email".to_string()));
}
